║                                                                           ║
╠═══════════════════════════════════════════════════════════════════════════╣
║                                                                           ║
║  Lineage:                                                                 ║
${lineageDisplay.split('\n').map(l => '║' + l.padEnd(75) + '║').join('\n')}
║                                                                           ║
╠═══════════════════════════════════════════════════════════════════════════╣
║                                                                           ║
║  Question for Depth 6:                                                    ║
║  ❝ ${this.state.questionFor6.padEnd(69)}║
║                                                                           ║
╚═══════════════════════════════════════════════════════════════════════════╝
`;
  }

